# Enriched from F5 iRules reference documentation.
"""HTTP2::active -- This command can be used to determine if a request or response is generated by HTTP/2."""

from __future__ import annotations

from ....compiler.side_effects import ConnectionSide, SideEffect, SideEffectTarget
from .._base import CommandDef
from ..models import CommandSpec, FormKind, FormSpec, HoverSnippet, ValidationSpec
from ..namespace_models import EventRequires
from ..signatures import Arity
from ._base import _IRULES_ONLY, register

_SOURCE = "https://clouddocs.f5.com/api/irules/HTTP2__active.html"


@register
class Http2ActiveCommand(CommandDef):
    name = "HTTP2::active"

    @classmethod
    def spec(cls) -> CommandSpec:
        return CommandSpec(
            name="HTTP2::active",
            dialects=_IRULES_ONLY,
            hover=HoverSnippet(
                summary="This command can be used to determine if a request or response is generated by HTTP/2.",
                synopsis=("HTTP2::active",),
                snippet="Returns 1 if the HTTP transaction is using HTTP/2. Returns 0 otherwise.",
                source=_SOURCE,
                examples=(
                    "when HTTP_REQUEST {\n"
                    "    if {[HTTP2::active]} {\n"
                    '        log local0. "request from HTTP/2 client"\n'
                    "    }\n"
                    "}"
                ),
                return_value="The return is 1 if the HTTP transaction is using HTTP/2, 0 otherwise.",
            ),
            forms=(
                FormSpec(
                    kind=FormKind.DEFAULT,
                    synopsis="HTTP2::active",
                ),
            ),
            validation=ValidationSpec(
                arity=Arity(),
            ),
            event_requires=EventRequires(
                transport="tcp",
                profiles=frozenset({"HTTP"}),
                also_in=frozenset({"MR_INGRESS", "MR_EGRESS"}),
            ),
            side_effect_hints=(
                SideEffect(
                    target=SideEffectTarget.HTTP2_STATE,
                    reads=True,
                    connection_side=ConnectionSide.BOTH,
                ),
            ),
        )
